const input = $input.first().json;

const tipoMap = {
  pizza: "pie",
  barra: "bar",
  linha: "line",
  donut: "doughnut"
};

const chart = {
  type: tipoMap[input.tipo] || "pie",
  data: {
    labels: input.labels,
    datasets: [{
      data: input.values,
      backgroundColor: [
        "#0F766E",
        "#14B8A6",
        "#2DD4BF",
        "#5EEAD4",
        "#99F6E4",
        "#CCFBF1"
      ]
    }]
  },
  options: {
    plugins: {
      title: {
        display: true,
        text: input.titulo
      },
      legend: {
        position: "bottom"
      }
    }
  }
};

return [{
  json: {
    telefone: input.telefone,
    legenda: input.legenda,
    url:
      "https://quickchart.io/chart?width=900&height=600&format=png&c=" +
      encodeURIComponent(JSON.stringify(chart))
  }
}];
